/* 사용자 정보 수정 */
UPDATE TB_USER
SET
    USER_NM = #{userNm},
    ORG_ID = #{orgId},
    EMAIL = #{email},
    PHONE = #{phone}
WHERE USER_ID = #{userId}

/* 사용자 정보 논리 삭제 */
UPDATE TB_USER
SET
    USE_YN = 'N',
    ACCT_STATUS_CD = '002'
WHERE USER_ID = #{userId}

/* 사용자 정보 복구 */
UPDATE TB_USER
SET
    USE_YN = 'Y',
    ACCT_STATUS_CD = '001'
WHERE USER_ID = #{userId}
